func codemapPrecisionHelp(w io.Writer) {
	fmt.Fprintln(w, "usage: ddocs codemap precision [-h] --benchmark PATH --suggestions PATH [--format {text,json}] [--output PATH]\n\nEvaluate a manually labeled codemap precision benchmark against a deterministic suggestion report.\n\noptions:\n  -h, --help            show this help message and exit\n  --benchmark PATH      labeled precision benchmark JSON\n  --suggestions PATH    source codemap benchmark report JSON\n  --format {text,json}  report format (default text)\n  --output PATH         write the report to a file instead of stdout")
}

func runCodemapPrecision(ctx context.Context, args []string, out, errOut io.Writer) int {
	if err := ctx.Err(); err != nil { return fail(errOut, err) }
	if helpRequested(args) {
		codemapPrecisionHelp(out)
		return 0
	}
	fs := flag.NewFlagSet("ddocs codemap precision", flag.ContinueOnError)
	fs.SetOutput(io.Discard)
	var benchmarkPath, suggestionsPath, output optionalString
	format := "text"
	fs.Var(&benchmarkPath, "benchmark", "labeled precision benchmark JSON")
	fs.Var(&suggestionsPath, "suggestions", "source codemap benchmark report JSON")
	fs.StringVar(&format, "format", format, "text or json")
	fs.Var(&output, "output", "report output file")
	if err := fs.Parse(args); err != nil {
		fmt.Fprintf(errOut, "ddocs codemap precision: error: %v\n", err)
		return 2
	}
	if fs.NArg() != 0 || !benchmarkPath.set || !suggestionsPath.set {
		fmt.Fprintln(errOut, "ddocs codemap precision: error: --benchmark and --suggestions are required")
		return 2
	}
	if format != "text" && format != "json" {
		fmt.Fprintf(errOut, "ddocs codemap precision: error: invalid --format %q; expected text or json\n", format)
		return 2
	}
	cwd, err := os.Getwd()
	if err != nil { return fail(errOut, err) }
	benchmarkFile, err := optionalInputPath(cwd, benchmarkPath)
	if err != nil { return fail(errOut, err) }
	suggestionsFile, err := optionalInputPath(cwd, suggestionsPath)
	if err != nil { return fail(errOut, err) }
	benchmarkReader, err := os.Open(benchmarkFile)
	if err != nil { return fail(errOut, err) }
	benchmark, err := codemapprecision.LoadBenchmark(benchmarkReader)
	benchmarkReader.Close()
	if err != nil { return fail(errOut, err) }
	suggestionsReader, err := os.Open(suggestionsFile)
	if err != nil { return fail(errOut, err) }
	report, err := codemapprecision.LoadSuggestionReport(suggestionsReader)
	suggestionsReader.Close()
	if err != nil { return fail(errOut, err) }
	evaluation, err := codemapprecision.Evaluate(benchmark, report)
	if err != nil { return fail(errOut, err) }
	var payload []byte
	if format == "json" {
		payload, err = jsonMarshalPrecision(evaluation)
	} else {
		payload = []byte(codemapprecision.FormatEvaluation(evaluation))
	}
	if err != nil { return fail(errOut, err) }
	if err := writePrecisionPayload(out, output, payload); err != nil { return fail(errOut, err) }
	return 0
}

func jsonMarshalPrecision(evaluation codemapprecision.Evaluation) ([]byte, error) {
	return json.MarshalIndent(evaluation, "", "  ")
}

func writePrecisionPayload(out io.Writer, output optionalString, payload []byte) error {
	if !output.set { _, err := out.Write(payload); return err }
	path, err := filepath.Abs(output.value)
	if err != nil { return err }
	if err := os.MkdirAll(filepath.Dir(path), 0o755); err != nil { return err }
	if err := os.WriteFile(path, payload, 0o644); err != nil { return err }
	fmt.Fprintf(out, "wrote codemap precision report to %s\n", path)
	return nil
}

