		writeTestFile(t, dataset, "{}")
		writeTestFile(t, trusted, "[]")
		runner := &recordingBenchmarkRunner{result: codemapBenchmarkResult{Payload: []byte("report\n"), Precision: 0.8, Recall: 0.6}}
